// /frontend/src/components/Radar.jsx
import React, { useEffect, useMemo, useRef, useState } from "react";
import { MapContainer, TileLayer, ZoomControl } from "react-leaflet";
import "leaflet/dist/leaflet.css";

function clamp(n, min, max) { return Math.max(min, Math.min(max, n)); }

export default function Radar({
  center = [33.7490, -84.3880], // Atlanta fallback
  zoom = 6,
  height = 320,
  className = "",
  refreshSeconds = 60,
}) {
  const [frameTime, setFrameTime] = useState(null);
  const [tilesLoaded, setTilesLoaded] = useState(false);
  const [tileError, setTileError] = useState(false);
  const mapRef = useRef(null);

  // Validate center/zoom so Leaflet always mounts cleanly
  const safeCenter = useMemo(() => {
    let [lat, lon] = Array.isArray(center) ? center : [33.7490, -84.3880];
    lat = Number.isFinite(lat) ? clamp(lat, -85, 85) : 33.7490;
    lon = Number.isFinite(lon) ? clamp(lon, -180, 180) : -84.3880;
    return [lat, lon];
  }, [center]);
  const safeZoom = useMemo(() => (Number.isFinite(zoom) ? clamp(zoom, 3, 12) : 6), [zoom]);

  // Get newest radar time initially + periodic refresh (RainViewer ~10‑min cadence)
  useEffect(() => {
    let alive = true;
    async function fetchTime() {
      try {
        const r = await fetch("https://api.rainviewer.com/public/weather-maps.json", { cache: "no-store" });
        const j = await r.json();
        const latest = j?.radar?.past?.at(-1)?.time ?? j?.radar?.nowcast?.[0]?.time ?? null;
        if (alive && latest) { setFrameTime((p) => (p !== latest ? latest : p)); setTileError(false); }
      } catch { /* soft fail; retry next tick */ }
    }
    fetchTime();
    const id = setInterval(fetchTime, Math.max(30, refreshSeconds) * 1000);
    return () => { alive = false; clearInterval(id); };
  }, [refreshSeconds]);

  const effectiveTime = useMemo(() => {
    if (typeof frameTime === "number") return frameTime;
    return Math.floor(Date.now() / (10 * 60 * 1000)) * (10 * 60); // seconds
  }, [frameTime]);

  const radarUrl = useMemo(
    () => `https://tilecache.rainviewer.com/v2/radar/${effectiveTime}/256/{z}/{x}/{y}/2/1_1.png`, // smooth=1, snow=1
    [effectiveTime]
  );

  return (
    <div className={`relative w-full ${className}`} style={{ height, borderRadius: 16, overflow: "hidden" }}>
      <MapContainer
        whenCreated={(m) => { mapRef.current = m; }}
        center={safeCenter}
        zoom={safeZoom}
        minZoom={3}
        maxZoom={12}
        style={{ width: "100%", height: "100%" }}
        // ✅ Always interactive
        scrollWheelZoom={true}
        dragging={true}
        touchZoom={true}
        doubleClickZoom={true}
        boxZoom={true}
        keyboard={true}
        // Keep the rest minimal
        attributionControl={false}
        zoomAnimation={true}
        fadeAnimation={false}
        markerZoomAnimation={false}
        preferCanvas={true}
      >
        {/* faint base so it’s never visually blank */}
        <TileLayer url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png" opacity={0.35} />
        {/* precipitation + snow */}
        <TileLayer
          url={radarUrl}
          opacity={0.9}
          eventHandlers={{
            tileload: () => setTilesLoaded(true),
            load: () => setTilesLoaded(true),
            tileerror: () => setTileError(true),
          }}
          updateWhenIdle={true}
          updateWhenZooming={false}
          keepBuffer={2}
          detectRetina={false}
        />
        <ZoomControl position="bottomright" />
      </MapContainer>

      {/* Loading / error overlay */}
      {(!tilesLoaded || tileError) && (
        <div className="pointer-events-none absolute inset-0 flex items-center justify-center">
          <div style={{
            padding: "6px 10px",
            borderRadius: 10,
            fontSize: 12,
            color: "white",
            backdropFilter: "blur(6px)",
            background: "rgba(0,0,0,0.35)"
          }}>
            {tileError ? "Radar tiles failed—retrying…" : "Loading latest radar…"}
          </div>
        </div>
      )}
    </div>
  );
}
